{"version":3,"file":"respec-w3c-common.js","sources":["../profiles/w3c-common.js","../src/core/expose-modules.js","../src/core/pubsubhub.js","../src/core/include-config.js","../src/core/override-configuration.js","../src/core/respec-ready.js","../src/core/post-process.js","../src/core/pre-process.js","../src/core/l10n.js","../node_modules/idb/build/esm/chunk.js","../node_modules/idb/build/esm/index.js","../node_modules/webidl2/lib/error.js","../node_modules/webidl2/lib/productions/base.js","../node_modules/webidl2/lib/validators/helpers.js","../node_modules/webidl2/lib/productions/type.js","../node_modules/webidl2/lib/productions/default.js","../node_modules/webidl2/lib/productions/array-base.js","../node_modules/webidl2/lib/productions/token.js","../node_modules/webidl2/lib/productions/extended-attributes.js","../node_modules/webidl2/lib/productions/argument.js","../node_modules/webidl2/lib/productions/operation.js","../node_modules/webidl2/lib/productions/attribute.js","../node_modules/webidl2/lib/productions/helpers.js","../node_modules/webidl2/lib/tokeniser.js","../node_modules/webidl2/lib/productions/enum.js","../node_modules/webidl2/lib/productions/includes.js","../node_modules/webidl2/lib/productions/typedef.js","../node_modules/webidl2/lib/productions/callback.js","../node_modules/webidl2/lib/productions/container.js","../node_modules/webidl2/lib/productions/constant.js","../node_modules/webidl2/lib/productions/iterable.js","../node_modules/webidl2/lib/productions/constructor.js","../node_modules/webidl2/lib/productions/interface.js","../node_modules/webidl2/lib/validators/interface.js","../node_modules/webidl2/lib/productions/mixin.js","../node_modules/webidl2/lib/productions/field.js","../node_modules/webidl2/lib/productions/dictionary.js","../node_modules/webidl2/lib/productions/namespace.js","../node_modules/webidl2/lib/productions/callback-interface.js","../node_modules/webidl2/lib/webidl2.js","../node_modules/webidl2/lib/writer.js","../node_modules/webidl2/lib/validator.js","../node_modules/hyperhtml/esm.js","../node_modules/marked/lib/marked.esm.js","../js/deps/builds/pluralize.js","../src/core/import-maps.js","../src/core/utils.js","../src/core/base-runner.js","../src/core/text-loader.js","../src/core/reindent.js","../src/core/markdown.js","../js/shortcut.js","../src/core/ui.js","../js/deps/builds/jquery.js","../src/core/jquery-enhanced.js","../src/core/location-hash.js","../src/core/LinterRule.js","../src/core/linter-rules/check-charset.js","../src/core/linter-rules/check-internal-slots.js","../src/core/linter-rules/check-punctuation.js","../src/core/linter.js","../src/core/linter-rules/local-refs-exist.js","../src/core/linter-rules/no-headingless-sections.js","../src/core/linter-rules/no-http-props.js","../src/core/linter-rules/privsec-section.js","../src/core/defaults.js","../src/core/dfn-map.js","../src/core/linter-rules/wpt-tests-exist.js","../src/w3c/defaults.js","../src/core/style.js","../src/w3c/style.js","../src/w3c/l10n.js","../src/core/github.js","../src/core/data-include.js","../src/w3c/templates/show-link.js","../src/w3c/templates/show-logo.js","../src/w3c/templates/show-people.js","../src/w3c/templates/headers.js","../src/w3c/templates/cgbg-headers.js","../src/w3c/templates/sotd.js","../src/w3c/templates/cgbg-sotd.js","../src/w3c/headers.js","../src/w3c/abstract.js","../src/core/data-transform.js","../src/core/data-abbr.js","../src/core/inline-idl-parser.js","../src/core/biblio-db.js","../src/core/biblio.js","../src/core/render-biblio.js","../src/core/inlines.js","../src/w3c/conformance.js","../src/core/dfn.js","../src/core/pluralize.js","../src/core/examples.js","../src/core/issues-notes.js","../src/core/best-practices.js","../src/core/figures.js","../src/core/dfn-finder.js","../src/core/webidl-clipboard.js","../src/core/webidl.js","../src/core/data-cite.js","../src/core/webidl-index.js","../src/core/xref-db.js","../src/core/xref.js","../src/core/link-to-dfn.js","../src/core/contrib.js","../src/core/fix-headers.js","../src/core/structure.js","../src/core/informative.js","../src/core/id-headers.js","../src/core/caniuse.js","../src/core/mdn-annotation.js","../src/core/exporter.js","../src/ui/save-html.js","../src/ui/search-specref.js","../src/ui/dfn-list.js","../src/ui/about-respec.js","../src/core/seo.js","../src/w3c/seo.js","../src/core/worker.js","../src/core/highlight.js","../src/core/data-tests.js","../src/core/list-sorter.js","../src/core/highlight-vars.js","../src/core/dfn-panel.js","../src/core/data-type.js","../src/core/algorithms.js","../src/core/anchor-expander.js","../src/core/custom-elements/rs-changelog.js","../src/core/custom-elements/index.js"],"sourcesContent":["\"use strict\";\n// In case everything else fails, we want the error\nwindow.addEventListener(\"error\", ev => {\n  console.error(ev.error, ev.message, ev);\n});\n\nconst modules = [\n  // order is significant\n  import(\"../src/core/base-runner.js\"),\n  import(\"../src/core/ui.js\"),\n  import(\"../src/core/jquery-enhanced.js\"),\n  import(\"../src/core/location-hash.js\"),\n  import(\"../src/core/l10n.js\"),\n  import(\"../src/w3c/defaults.js\"),\n  import(\"../src/core/style.js\"),\n  import(\"../src/w3c/style.js\"),\n  import(\"../src/w3c/l10n.js\"),\n  import(\"../src/core/github.js\"),\n  import(\"../src/core/data-include.js\"),\n  import(\"../src/core/markdown.js\"),\n  import(\"../src/core/reindent.js\"),\n  import(\"../src/w3c/headers.js\"),\n  import(\"../src/w3c/abstract.js\"),\n  import(\"../src/core/data-transform.js\"),\n  import(\"../src/core/data-abbr.js\"),\n  import(\"../src/core/inlines.js\"),\n  import(\"../src/w3c/conformance.js\"),\n  import(\"../src/core/dfn.js\"),\n  import(\"../src/core/pluralize.js\"),\n  import(\"../src/core/examples.js\"),\n  import(\"../src/core/issues-notes.js\"),\n  import(\"../src/core/best-practices.js\"),\n  import(\"../src/core/figures.js\"),\n  import(\"../src/core/webidl.js\"),\n  import(\"../src/core/data-cite.js\"),\n  import(\"../src/core/biblio.js\"),\n  import(\"../src/core/webidl-index.js\"),\n  import(\"../src/core/link-to-dfn.js\"),\n  import(\"../src/core/render-biblio.js\"),\n  import(\"../src/core/contrib.js\"),\n  import(\"../src/core/fix-headers.js\"),\n  import(\"../src/core/structure.js\"),\n  import(\"../src/core/informative.js\"),\n  import(\"../src/core/id-headers.js\"),\n  import(\"../src/core/caniuse.js\"),\n  import(\"../src/core/mdn-annotation.js\"),\n  import(\"../src/ui/save-html.js\"),\n  import(\"../src/ui/search-specref.js\"),\n  import(\"../src/ui/dfn-list.js\"),\n  import(\"../src/ui/about-respec.js\"),\n  import(\"../src/core/seo.js\"),\n  import(\"../src/w3c/seo.js\"),\n  import(\"../src/core/highlight.js\"),\n  import(\"../src/core/webidl-clipboard.js\"),\n  import(\"../src/core/data-tests.js\"),\n  import(\"../src/core/list-sorter.js\"),\n  import(\"../src/core/highlight-vars.js\"),\n  import(\"../src/core/dfn-panel.js\"),\n  import(\"../src/core/data-type.js\"),\n  import(\"../src/core/algorithms.js\"),\n  import(\"../src/core/anchor-expander.js\"),\n  import(\"../src/core/custom-elements/index.js\"),\n  /* Linter must be the last thing to run */\n  import(\"../src/core/linter.js\"),\n];\n\nasync function domReady() {\n  if (document.readyState === \"loading\") {\n    await new Promise(resolve =>\n      document.addEventListener(\"DOMContentLoaded\", resolve)\n    );\n  }\n}\n\n(async () => {\n  const [runner, { ui }, ...plugins] = await Promise.all(modules);\n  try {\n    ui.show();\n    await domReady();\n    await runner.runAll(plugins);\n  } finally {\n    ui.enable();\n  }\n})().catch(err => {\n  console.error(err);\n});\n","// @ts-check\nconst inAmd = !!window.require;\nif (!inAmd) {\n  /**\n   * @type {any}\n   * @param {string[]} deps\n   * @param {(...modules: any[]) => void} callback\n   */\n  const require = function(deps, callback) {\n    const modules = deps.map(dep => {\n      if (!(dep in window.require.modules)) {\n        throw new Error(`Unsupported dependency name: ${dep}`);\n      }\n      return window.require.modules[dep];\n    });\n    Promise.all(modules).then(results => callback(...results));\n  };\n  require.modules = {};\n  window.require = require;\n}\n\n/**\n * @param {string} name\n * @param {object | Promise<object>} object\n */\nexport function expose(name, object) {\n  if (!inAmd) {\n    window.require.modules[name] = object;\n  }\n}\n","// @ts-check\nimport { expose } from \"./expose-modules.js\";\n\n/**\n * Module core/pubsubhub\n *\n * Returns a singleton that can be used for message broadcasting\n * and message receiving. Replaces legacy \"msg\" code in ReSpec.\n */\nexport const name = \"core/pubsubhub\";\n\nconst subscriptions = new Map();\n\nexport function pub(topic, ...data) {\n  if (!subscriptions.has(topic)) {\n    return; // Nothing to do...\n  }\n  Array.from(subscriptions.get(topic)).forEach(cb => {\n    try {\n      cb(...data);\n    } catch (err) {\n      pub(\n        \"error\",\n        `Error when calling function ${cb.name}. See developer console.`\n      );\n      console.error(err);\n    }\n  });\n  if (window.parent === window.self) {\n    return;\n  }\n  // If this is an iframe, postMessage parent (used in testing).\n  const args = data\n    // to structured clonable\n    .map(arg => String(JSON.stringify(arg.stack || arg)));\n  window.parent.postMessage({ topic, args }, window.parent.location.origin);\n}\n/**\n * Subscribes to a message type.\n *\n * @param  {string} topic        The topic to subscribe to (e.g., \"start-all\")\n * @param  {Function} cb         Callback function\n * @param  {Object} [opts]\n * @param  {Boolean} [opts.once] Add prop \"once\" for single notification.\n * @return {Object}              An object that should be considered opaque,\n *                               used for unsubscribing from messages.\n */\nexport function sub(topic, cb, opts = { once: false }) {\n  if (opts.once) {\n    return sub(topic, function wrapper(...args) {\n      unsub({ topic, cb: wrapper });\n      cb(...args);\n    });\n  }\n  if (subscriptions.has(topic)) {\n    subscriptions.get(topic).add(cb);\n  } else {\n    subscriptions.set(topic, new Set([cb]));\n  }\n  return { topic, cb };\n}\n/**\n * Unsubscribe from messages.\n *\n * @param {Object} opaque The object that was returned from calling sub()\n */\nexport function unsub({ topic, cb }) {\n  // opaque is whatever is returned by sub()\n  const callbacks = subscriptions.get(topic);\n  if (!callbacks || !callbacks.has(cb)) {\n    console.warn(\"Already unsubscribed:\", topic, cb);\n    return false;\n  }\n  return callbacks.delete(cb);\n}\n\nsub(\"error\", err => {\n  console.error(err, err.stack);\n});\n\nsub(\"warn\", str => {\n  console.warn(str);\n});\n\nexpose(name, { sub });\n","// @ts-check\n// Module core/include-config\n// Inject's the document's configuration into the head as JSON.\nimport { sub } from \"./pubsubhub.js\";\nexport const name = \"core/include-config\";\n\nconst userConfig = {};\nconst amendConfig = newValues => Object.assign(userConfig, newValues);\nconst removeList = [\"githubToken\", \"githubUser\"];\n\nsub(\"start-all\", amendConfig);\nsub(\"amend-user-config\", amendConfig);\nsub(\"end-all\", () => {\n  const script = document.createElement(\"script\");\n  script.id = \"initialUserConfig\";\n  script.type = \"application/json\";\n  for (const prop of removeList) {\n    if (prop in userConfig) delete userConfig[prop];\n  }\n  script.innerHTML = JSON.stringify(userConfig, null, 2);\n  document.head.appendChild(script);\n});\n","// @ts-check\n// Module core/override-configuration\n// A helper module that makes it possible to override settings specified in respecConfig\n// by passing them as a query string. This is useful when you just want to make a few\n// tweaks to a document before generating the snapshot, without mucking with the source.\n// For example, you can change the status and date by appending:\n//      ?specStatus=LC&publishDate=2012-03-15\nimport { pub, sub } from \"./pubsubhub.js\";\n\nexport const name = \"core/override-configuration\";\n\nfunction overrideConfig(config) {\n  // For legacy reasons, we still support both \";\" and \"&\"\n  const searchQuery = document.location.search.replace(/;/g, \"&\");\n  const params = new URLSearchParams(searchQuery);\n  const overrideProps = Array.from(params)\n    .filter(([key, value]) => !!key && !!value)\n    .map(([codedKey, codedValue]) => {\n      const key = decodeURIComponent(codedKey);\n      const decodedValue = decodeURIComponent(codedValue.replace(/%3D/g, \"=\"));\n      let value;\n      try {\n        value = JSON.parse(decodedValue);\n      } catch {\n        value = decodedValue;\n      }\n      return { key, value };\n    })\n    .reduce((collector, { key, value }) => {\n      collector[key] = value;\n      return collector;\n    }, {});\n  Object.assign(config, overrideProps);\n  pub(\"amend-user-config\", overrideProps);\n}\nsub(\"start-all\", overrideConfig, { once: true });\n","// @ts-check\n/**\n * This Module adds a `respecIsReady` property to the document object.\n * The property returns a promise that settles when ReSpec finishes\n * processing the document.\n */\nimport { sub } from \"./pubsubhub.js\";\nexport const name = \"core/respec-ready\";\n\n/** @type {Promise<void>} */\nconst respecDonePromise = new Promise(resolve => {\n  sub(\"end-all\", resolve, { once: true });\n});\n\nObject.defineProperty(document, \"respecIsReady\", {\n  get() {\n    return respecDonePromise;\n  },\n});\n","// @ts-check\n/**\n * Module core/post-process\n *\n * Corresponds to respecConfig.postProcess and config.afterEnd.\n *  - postProcess: an array of functions that get called\n *      after processing finishes. This is not recommended and the feature is not\n *      tested. Use with care, if you know what you're doing. Chances are you really\n *      want to be using a new module with your own profile.\n *  - afterEnd: final thing that is called.\n */\nimport { pub, sub } from \"./pubsubhub.js\";\n\nexport const name = \"core/post-process\";\n\nlet doneResolver;\nexport const done = new Promise(resolve => {\n  doneResolver = resolve;\n});\n\nsub(\n  \"plugins-done\",\n  async config => {\n    const result = [];\n    if (Array.isArray(config.postProcess)) {\n      const promises = config.postProcess\n        .filter(f => {\n          const isFunction = typeof f === \"function\";\n          if (!isFunction) {\n            pub(\"error\", \"Every item in `postProcess` must be a JS function.\");\n          }\n          return isFunction;\n        })\n        .map(async f => {\n          try {\n            return await f(config, document);\n          } catch (err) {\n            pub(\n              \"error\",\n              `Function ${f.name} threw an error during \\`postProcess\\`. See developer console.`\n            );\n            console.error(err);\n          }\n        });\n      const values = await Promise.all(promises);\n      result.push(...values);\n    }\n    if (typeof config.afterEnd === \"function\") {\n      result.push(await config.afterEnd(config, document));\n    }\n    doneResolver(result);\n  },\n  { once: true }\n);\n","// @ts-check\n/**\n * Module core/pre-process\n *\n * Corresponds to respecConfig.preProcess.\n *  - preProcess: an array of functions that get called\n *      before anything else happens. This is not recommended and the feature is not\n *      tested. Use with care, if you know what you're doing. Chances are you really\n *      want to be using a new module with your own profile\n */\nimport { pub, sub } from \"./pubsubhub.js\";\n\nexport const name = \"core/pre-process\";\n\nlet doneResolver;\nexport const done = new Promise(resolve => {\n  doneResolver = resolve;\n});\n\nsub(\n  \"start-all\",\n  async config => {\n    const result = [];\n    if (Array.isArray(config.preProcess)) {\n      const promises = config.preProcess\n        .filter(f => {\n          const isFunction = typeof f === \"function\";\n          if (!isFunction) {\n            pub(\"error\", \"Every item in `preProcess` must be a JS function.\");\n          }\n          return isFunction;\n        })\n        .map(async f => {\n          try {\n            return await f(config, document);\n          } catch (err) {\n            pub(\n              \"error\",\n              `Function ${f.name} threw an error during \\`preProcess\\`. See developer console.`\n            );\n            console.error(err);\n          }\n        });\n      const values = await Promise.all(promises);\n      result.push(...values);\n    }\n    doneResolver(result);\n  },\n  { once: true }\n);\n","// @ts-check\n/**\n * Module core/l10n\n *\n * Looks at the lang attribute on the root element and uses it\n * to manage the config.l10n object so that other parts of the system can\n * localize their text.\n */\n\nexport const name = \"core/l10n\";\n\nconst html = document.documentElement;\nif (html && !html.hasAttribute(\"lang\")) {\n  html.lang = \"en\";\n  if (!html.hasAttribute(\"dir\")) {\n    html.dir = \"ltr\";\n  }\n}\n\nexport const l10n = {};\n\nexport const lang = html.lang;\n\nexport function run(config) {\n  config.l10n = l10n[lang] || l10n.en;\n}\n","const instanceOfAny = (object, constructors) => constructors.some(c => object instanceof c);\n\nlet idbProxyableTypes;\r\nlet cursorAdvanceMethods;\r\n// This is a function to prevent it throwing up in node environments.\r\nfunction getIdbProxyableTypes() {\r\n    return (idbProxyableTypes ||\r\n        (idbProxyableTypes = [\r\n            IDBDatabase,\r\n            IDBObjectStore,\r\n            IDBIndex,\r\n            IDBCursor,\r\n            IDBTransaction,\r\n        ]));\r\n}\r\n// This is a function to prevent it throwing up in node environments.\r\nfunction getCursorAdvanceMethods() {\r\n    return (cursorAdvanceMethods ||\r\n        (cursorAdvanceMethods = [\r\n            IDBCursor.prototype.advance,\r\n            IDBCursor.prototype.continue,\r\n            IDBCursor.prototype.continuePrimaryKey,\r\n        ]));\r\n}\r\nconst cursorRequestMap = new WeakMap();\r\nconst transactionDoneMap = new WeakMap();\r\nconst transactionStoreNamesMap = new WeakMap();\r\nconst transformCache = new WeakMap();\r\nconst reverseTransformCache = new WeakMap();\r\nfunction promisifyRequest(request) {\r\n    const promise = new Promise((resolve, reject) => {\r\n        const unlisten = () => {\r\n            request.removeEventListener('success', success);\r\n            request.removeEventListener('error', error);\r\n        };\r\n        const success = () => {\r\n            resolve(wrap(request.result));\r\n            unlisten();\r\n        };\r\n        const error = () => {\r\n            reject(request.error);\r\n            unlisten();\r\n        };\r\n        request.addEventListener('success', success);\r\n        request.addEventListener('error', error);\r\n    });\r\n    promise\r\n        .then(value => {\r\n        // Since cursoring reuses the IDBRequest (*sigh*), we cache it for later retrieval\r\n        // (see wrapFunction).\r\n        if (value instanceof IDBCursor) {\r\n            cursorRequestMap.set(value, request);\r\n        }\r\n        // Catching to avoid \"Uncaught Promise exceptions\"\r\n    })\r\n        .catch(() => { });\r\n    // This mapping exists in reverseTransformCache but doesn't doesn't exist in transformCache. This\r\n    // is because we create many promises from a single IDBRequest.\r\n    reverseTransformCache.set(promise, request);\r\n    return promise;\r\n}\r\nfunction cacheDonePromiseForTransaction(tx) {\r\n    // Early bail if we've already created a done promise for this transaction.\r\n    if (transactionDoneMap.has(tx))\r\n        return;\r\n    const done = new Promise((resolve, reject) => {\r\n        const unlisten = () => {\r\n            tx.removeEventListener('complete', complete);\r\n            tx.removeEventListener('error', error);\r\n            tx.removeEventListener('abort', error);\r\n        };\r\n        const complete = () => {\r\n            resolve();\r\n            unlisten();\r\n        };\r\n        const error = () => {\r\n            reject(tx.error);\r\n            unlisten();\r\n        };\r\n        tx.addEventListener('complete', complete);\r\n        tx.addEventListener('error', error);\r\n        tx.addEventListener('abort', error);\r\n    });\r\n    // Cache it for later retrieval.\r\n    transactionDoneMap.set(tx, done);\r\n}\r\nlet idbProxyTraps = {\r\n    get(target, prop, receiver) {\r\n        if (target instanceof IDBTransaction) {\r\n            // Special handling for transaction.done.\r\n            if (prop === 'done')\r\n                return transactionDoneMap.get(target);\r\n            // Polyfill for objectStoreNames because of Edge.\r\n            if (prop === 'objectStoreNames') {\r\n                return target.objectStoreNames || transactionStoreNamesMap.get(target);\r\n            }\r\n            // Make tx.store return the only store in the transaction, or undefined if there are many.\r\n            if (prop === 'store') {\r\n                return receiver.objectStoreNames[1]\r\n                    ? undefined\r\n                    : receiver.objectStore(receiver.objectStoreNames[0]);\r\n            }\r\n        }\r\n        // Else transform whatever we get back.\r\n        return wrap(target[prop]);\r\n    },\r\n    has(target, prop) {\r\n        if (target instanceof IDBTransaction &&\r\n            (prop === 'done' || prop === 'store')) {\r\n            return true;\r\n        }\r\n        return prop in target;\r\n    },\r\n};\r\nfunction addTraps(callback) {\r\n    idbProxyTraps = callback(idbProxyTraps);\r\n}\r\nfunction wrapFunction(func) {\r\n    // Due to expected object equality (which is enforced by the caching in `wrap`), we\r\n    // only create one new func per func.\r\n    // Edge doesn't support objectStoreNames (booo), so w